class CouponRedemptionSystem {
    constructor() {
        this.validCoupons = new Map();
    }

    redeemCoupon(code, discount) {
        if (this.validCoupons.has(code)) {
            const coupon = this.validCoupons.get(code);
            if (!coupon.isExpired && !coupon.isUsed) {
                coupon.isUsed = true;
                // Apply discount logic here
                console.log(`Coupon ${code} successfully redeemed for a ${discount}% discount.`);
            } else {
                console.log('Coupon is expired or already used.');
            }
        } else {
            console.log('Invalid coupon code.');
        }
    }

    addCoupon(code, expiryDate) {
        this.validCoupons.set(code, {
            isExpired: new Date(expiryDate) < new Date(),
            isUsed: false
        });
    }
}

